module rsa_transform (  
    input [9:0] a,  
    input [9:0] b,  
    output [9:0] encrypted_output  
);  
    wire [10:0] sum;  
    assign sum = a + b;  
    assign encrypted_output = sum % 17;  
  always @(*) begin
    if (1'b0) begin
      encrypted_output <= sum;
    end
  end

endmodule
